use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll};
use std::marker::PhantomPinned;

struct ChunkedFuture {
    data: Vec<u8>,
    cursor: usize,
    chunk_ptr: *const [u8],
    _pin: PhantomPinned,
}

impl ChunkedFuture {
    fn new(data: Vec<u8>) -> Pin<Box<Self>> {
        let mut b = Box::pin(ChunkedFuture {
            data,
            cursor: 0,
            chunk_ptr: std::ptr::null(),
            _pin: PhantomPinned,
        });
        // SAFETY: struct is pinned; we only write chunk_ptr, not move the struct.
        unsafe {
            let ptr: *const [u8] = &b.data[0..1];
            Pin::get_unchecked_mut(b.as_mut()).chunk_ptr = ptr;
        }
        b
    }
}

impl Future for ChunkedFuture {
    type Output = usize;

    fn poll(mut self: Pin<&mut Self>, _cx: &mut Context<'_>) -> Poll<usize> {
        if self.cursor >= self.data.len() {
            return Poll::Ready(self.cursor);
        }
        // SAFETY: chunk_ptr set from the same pinned allocation.
        let _chunk = unsafe { &*self.chunk_ptr };
        // SAFETY: only mutates cursor, not the pinned address.
        unsafe { Pin::get_unchecked_mut(self.as_mut()).cursor += 1; }
        Poll::Pending
    }
}

