use std::collections::VecDeque;

struct Slab {
    data: Vec<i32>,
    free: VecDeque<usize>,
}

impl Slab {
    fn new(capacity: usize) -> Self {
        Slab {
            data: vec![0; capacity],
            free: (0..capacity).collect(),
        }
    }

    fn alloc(&mut self, value: i32) -> Option<usize> {
        let idx = self.free.pop_front()?;
        self.data[idx] = value;
        Some(idx)
    }

    fn free(&mut self, idx: usize) {
        self.data[idx] = 0;
        self.free.push_back(idx);
    }

    fn get(&self, idx: usize) -> i32 { self.data[idx] }
}

