    let mut slab = Slab::new(4);
    let a = slab.alloc(10).unwrap();
    let b = slab.alloc(20).unwrap();
    println!("{} {}", slab.get(a), slab.get(b));
    slab.free(a);
    let c = slab.alloc(30).unwrap();
    println!("reused slot {}: {}", c, slab.get(c));
}

