use std::pin::Pin;
use std::marker::PhantomPinned;

// A genuinely self-referential struct needs !Unpin.
struct SelfRef {
    data: u32,
    ptr: *const u32,
    _pin: PhantomPinned,
}

impl SelfRef {
    fn new(data: u32) -> Pin<Box<Self>> {
        let mut b = Box::pin(SelfRef {
            data,
            ptr: std::ptr::null(),
            _pin: PhantomPinned,
        });
        let p: *const u32 = &b.data;
        // SAFETY: only writes `ptr`; the Box is pinned and will not move.
        unsafe { Pin::get_unchecked_mut(b.as_mut()).ptr = p; }
        b
    }

    fn read(self: Pin<&Self>) -> u32 {
        // SAFETY: ptr was set from the same pinned allocation and is valid.
        unsafe { *self.ptr }
    }
}

fn main() {
    let s = SelfRef::new(42);
    println!("{}", s.as_ref().read());
