use std::pin::Pin;
use std::marker::PhantomPinned;

struct Ring {
    data: [u8; 8],
    head: *const u8,
    _pin: PhantomPinned,
}

impl Ring {
    fn new() -> Pin<Box<Self>> {
        // Step 1: create the struct with a null pointer
        let mut b = Box::pin(Ring {
            data: [1, 2, 3, 4, 5, 6, 7, 8],
            head: std::ptr::null(),
            _pin: PhantomPinned,
        });
        // Step 2: now that the allocation is stable, set head
        let ptr = b.data.as_ptr();
        // SAFETY: only writes `head`; Box is pinned, allocation will not move.
        unsafe { Pin::get_unchecked_mut(b.as_mut()).head = ptr; }
        b
    }

    fn peek(self: Pin<&Self>) -> u8 {
        // SAFETY: head points into the same pinned allocation.
        unsafe { *self.head }
    }
}

fn main() {
    let ring = Ring::new();
    println!("first byte: {}", ring.as_ref().peek());
}
